import sslimport osimport numpy as npimport timeos.environ["CUDA_VISIBLE_DEVICES"] = "5"os.environ['TF_CPP_MIN_LOG_LEVEL'] = '3'os.environ['PYTHONWARNINGS'] = 'ignore'ssl._create_default_https_context = ssl._create_unverified_contextimport torchimport torch.nn as nnimport torch.nn.functional as Fimport argparseimport pandas as pdimport nibabel as nibfrom torch.autograd import Variablefrom math import expimport loggingimport warningslogging.getLogger('tensorflow').setLevel(logging.ERROR)warnings.filterwarnings("ignore", module="torchvision.io.image")warnings.filterwarnings("ignore", message="Failed to load image Python extension")warnings.filterwarnings("ignore", category=FutureWarning, module="timm.models.layers")from utils import getters, settersfrom utils.functions import (AverageMeter, registerSTModel, dice_eval, computeJacDetVal, computeSDLogJ, compute_HD95, jacobian_determinant)from utils.loss import NccLossdef extract_unigradicon_flow(model, moving, fixed, debug=False):    """    从 UniGradICON 模型提取初始位移场（体素单位）    Args:        model:  预训练 UniGradICON 模型实例        moving: 移动图像 [B, C, H, W, D]        fixed:  固定图像 [B, C, H, W, D]    Returns:        flow:   位移场 [B, 3, H, W, D]（体素单位）    """    original_shape = moving.shape[2:]    expected_shape = (175, 175, 175)    # 调整输入尺寸至模型期望尺寸    if original_shape != expected_shape:        if debug:            print(f"调整输入尺寸: {original_shape} → {expected_shape}")        moving_in = F.interpolate(moving, size=expected_shape, mode='trilinear', align_corners=False)        fixed_in  = F.interpolate(fixed,  size=expected_shape, mode='trilinear', align_corners=False)    else:        moving_in = moving        fixed_in  = fixed    with torch.no_grad():        _ = model(moving_in, fixed_in)        phi_AB   = model.phi_AB_vectorfield   # 归一化坐标系下的变形场        identity = model.identity_map        flow_normalized = phi_AB - identity        # 转换为体素单位        D, H, W = phi_AB.shape[2:]        scaling = torch.tensor(            [D - 1, H - 1, W - 1],            device=flow_normalized.device,            dtype=flow_normalized.dtype        ).view(1, 3, 1, 1, 1)        flow_voxel = flow_normalized * scaling    # 将流场缩放回原始图像尺寸    if original_shape != expected_shape:        if debug:            print(f"调整流场回原始尺寸: {expected_shape} → {original_shape}")        flow_voxel = F.interpolate(flow_voxel, size=original_shape, mode='trilinear', align_corners=False)        for i in range(3):            flow_voxel[:, i] *= original_shape[i] / expected_shape[i]    if debug:        print(f"  [UniGradICON] Flow shape: {flow_voxel.shape}")        print(f"  [UniGradICON] Flow range: [{flow_voxel.min():.3f}, {flow_voxel.max():.3f}]")    return flow_voxelclass Grad3d(nn.Module):    """一阶梯度正则化损失"""    def __init__(self, penalty='l1', loss_mult=None):        super().__init__()        self.penalty   = penalty        self.loss_mult = loss_mult    def forward(self, y_pred):        dy = torch.abs(y_pred[:, :, 1:, :, :] - y_pred[:, :, :-1, :, :])        dx = torch.abs(y_pred[:, :, :, 1:, :] - y_pred[:, :, :, :-1, :])        dz = torch.abs(y_pred[:, :, :, :, 1:] - y_pred[:, :, :, :, :-1])        if self.penalty == 'l2':            dy, dx, dz = dy * dy, dx * dx, dz * dz        grad = (torch.mean(dx) + torch.mean(dy) + torch.mean(dz)) / 3.0        if self.loss_mult is not None:            grad *= self.loss_mult        return graddef gaussian(window_size, sigma):    gauss = torch.Tensor([        exp(-(x - window_size // 2) ** 2 / float(2 * sigma ** 2))        for x in range(window_size)    ])    return gauss / gauss.sum()def create_window_3D(window_size, channel):    _1D = gaussian(window_size, 1.5).unsqueeze(1)    _2D = _1D.mm(_1D.t())    _3D = _1D.mm(_2D.reshape(1, -1)).reshape(        window_size, window_size, window_size    ).float().unsqueeze(0).unsqueeze(0)    return Variable(_3D.expand(channel, 1, window_size, window_size, window_size).contiguous())def _ssim_3D(img1, img2, window, window_size, channel, size_average=True):    mu1 = F.conv3d(img1, window, padding=window_size // 2, groups=channel)    mu2 = F.conv3d(img2, window, padding=window_size // 2, groups=channel)    mu1_sq, mu2_sq, mu1_mu2 = mu1.pow(2), mu2.pow(2), mu1 * mu2    sigma1_sq = F.conv3d(img1 * img1, window, padding=window_size // 2, groups=channel) - mu1_sq    sigma2_sq = F.conv3d(img2 * img2, window, padding=window_size // 2, groups=channel) - mu2_sq    sigma12   = F.conv3d(img1 * img2, window, padding=window_size // 2, groups=channel) - mu1_mu2    C1, C2 = 0.01 ** 2, 0.03 ** 2    ssim_map = ((2 * mu1_mu2 + C1) * (2 * sigma12 + C2)) / \               ((mu1_sq + mu2_sq + C1) * (sigma1_sq + sigma2_sq + C2))    return ssim_map.mean() if size_average else ssim_map.mean(1).mean(1).mean(1)class SSIM3D(nn.Module):    def __init__(self, window_size=11, size_average=True):        super().__init__()        self.window_size  = window_size        self.size_average = size_average        self.channel      = 1        self.window       = create_window_3D(window_size, self.channel)    def forward(self, img1, img2):        (_, channel, _, _, _) = img1.size()        if channel == self.channel and self.window.data.type() == img1.data.type():            window = self.window        else:            window = create_window_3D(self.window_size, channel)            if img1.is_cuda:                window = window.cuda(img1.get_device())            window = window.type_as(img1)            self.window, self.channel = window, channel        return 1 - _ssim_3D(img1, img2, window, self.window_size, channel, self.size_average)class MultiScaleNCC(nn.Module):    """多尺度归一化互相关损失"""    def __init__(self, window_sizes=(5, 9, 13), weights=None):        super().__init__()        self.ncc_losses = [NccLoss([ws, ws, ws]) for ws in window_sizes]        weights = weights or [0.5, 0.3, 0.2]        total = sum(weights)        self.weights = [w / total for w in weights]    def forward(self, fixed, moving):        return sum(w * loss(fixed, moving) for loss, w in zip(self.ncc_losses, self.weights))def unsupervised_optimization(moving, fixed, initial_flow, current_shape, config, debug=False):    """    无监督测试时实例优化    Args:        moving:        移动图像 [B, C, H, W, D]        fixed:         固定图像 [B, C, H, W, D]        initial_flow:  初始位移场 [B, 3, H, W, D]        current_shape: 图像空间尺寸 (H, W, D)        config:        优化配置字典    Returns:        disp_hr: 优化后的位移场 [B, 3, H, W, D]    """    device = moving.device    H, W, D = current_shape    max_iterations = config.get('max_iterations', 10)    initial_lr     = config.get('learning_rate', 0.025)    grid_sp_adam   = config.get('grid_sp_adam', 1)    lambda_sim     = config.get('lambda_sim', 1.0)    lambda_reg     = config.get('lambda_reg', 1.0)    lambda_ssim    = config.get('lambda_ssim', 2.0)    with torch.enable_grad():        # 初始化可优化位移场（以 Conv3d 权重形式存储）        initial_flow_lr = F.interpolate(            initial_flow.detach(),            size=(H // grid_sp_adam, W // grid_sp_adam, D // grid_sp_adam),            mode='trilinear', align_corners=False        )        net = nn.Sequential(            nn.Conv3d(3, 1, (H // grid_sp_adam, W // grid_sp_adam, D // grid_sp_adam), bias=False)        )        net[0].weight.data[:] = (initial_flow_lr / grid_sp_adam).float().cpu().data        net.to(device)        optimizer = torch.optim.Adam(net.parameters(), lr=initial_lr, betas=(0.9, 0.999))        scheduler = torch.optim.lr_scheduler.ReduceLROnPlateau(            optimizer, mode='min', factor=0.5, patience=2, verbose=False        )        with torch.no_grad():            grid0 = F.affine_grid(                torch.eye(3, 4).unsqueeze(0).to(device),                (1, 1, H // grid_sp_adam, W // grid_sp_adam, D // grid_sp_adam),                align_corners=False            )            scale = torch.tensor([                (H // grid_sp_adam - 1) / 2,                (W // grid_sp_adam - 1) / 2,                (D // grid_sp_adam - 1) / 2            ]).to(device)            patch_image_fix = F.avg_pool3d(fixed, grid_sp_adam, stride=grid_sp_adam)        ncc_loss_fn  = MultiScaleNCC(window_sizes=(5, 9, 13))        reg_loss_fn  = Grad3d()        ssim_loss_fn = SSIM3D()        best_loss        = float('inf')        best_weight      = net[0].weight.data.clone()        patience_counter = 0        max_patience     = 3        for it in range(max_iterations):            optimizer.zero_grad()            disp_sample   = net[0].weight.permute(0, 2, 3, 4, 1)            grid_disp     = (grid0.view(-1, 3).to(device).float()                             + (disp_sample.view(-1, 3) / scale).flip(1).float())            grid_reshaped = grid_disp.view(                1, H // grid_sp_adam, W // grid_sp_adam, D // grid_sp_adam, 3            ).to(device)            warped_image = F.grid_sample(                F.avg_pool3d(moving, grid_sp_adam, stride=grid_sp_adam).float(),                grid_reshaped, align_corners=False, mode='bilinear'            )            ncc_loss  = lambda_sim  * ncc_loss_fn(patch_image_fix, warped_image)            reg_loss  = lambda_reg  * reg_loss_fn(net[0].weight)            ssim_loss = lambda_ssim * ssim_loss_fn(patch_image_fix, warped_image)            total_loss = ncc_loss + reg_loss + ssim_loss            total_loss.backward()            torch.nn.utils.clip_grad_norm_(net.parameters(), max_norm=1.0)            optimizer.step()            current_loss = total_loss.item()            if current_loss < best_loss:                best_loss        = current_loss                best_weight      = net[0].weight.data.clone()                patience_counter = 0                if debug and it % 2 == 0:                    print(f"iter {it:2d}: loss={current_loss:.4f} "                          f"(ncc={ncc_loss.item():.3f}, reg={reg_loss.item():.3f}, "                          f"ssim={ssim_loss.item():.3f}) ★")            else:                patience_counter += 1                if debug and it % 2 == 0:                    print(f"iter {it:2d}: loss={current_loss:.4f} "                          f"(patience {patience_counter}/{max_patience})")            if patience_counter >= max_patience:                if debug:                    print(f"提前停止: 损失连续 {max_patience} 次迭代未改善")                break            if it % 2 == 0:                scheduler.step(current_loss)        net[0].weight.data = best_weight        with torch.no_grad():            disp_hr = F.interpolate(                net[0].weight * grid_sp_adam,                size=(H, W, D), mode='trilinear', align_corners=False            )            if debug:                print(f"优化完成: 最终 loss={best_loss:.4f}")    return disp_hrdef unified_registration(moving, fixed, pretrained_model, config):    """    UniGradICON 预训练初始化 + 测试时实例优化配准    Args:        moving:           移动图像 [B, C, H, W, D]        fixed:            固定图像 [B, C, H, W, D]        pretrained_model: 预训练 UniGradICON 模型        config:           配准配置字典    Returns:        initial_flow:      初始位移场 [B, 3, H, W, D]        optimized_flow:    优化后位移场 [B, 3, H, W, D]        initial_flow_time: 初始流场预测耗时（秒）        optimization_time: 实例优化耗时（秒）    """    debug      = config.get('debug', False)    moving     = moving.float().contiguous()    fixed      = fixed.float().contiguous()    batch_size = moving.shape[0]    if debug:        print("\n" + "=" * 80)        print("  开始 UniGradICON 配准流程")        print(f"  原始尺寸: {moving.shape[2:]} | 模型期望尺寸: (175, 175, 175)")        print("=" * 80)    # 步骤1: 初始流场预测    if torch.cuda.is_available():        torch.cuda.synchronize()    t0 = time.time()    initial_flow = extract_unigradicon_flow(pretrained_model, moving, fixed, debug)    if torch.cuda.is_available():        torch.cuda.synchronize()    initial_flow_time = time.time() - t0    # 步骤2: 实例优化    if config.get('max_iterations', 0) > 0:        if debug:            print(f"开始实例优化 (max_iterations={config['max_iterations']})")            print("-" * 80)        if torch.cuda.is_available():            torch.cuda.synchronize()        t1 = time.time()        optimized_flow = unsupervised_optimization(            moving, fixed, initial_flow, moving.shape[2:], config, debug        )        if torch.cuda.is_available():            torch.cuda.synchronize()        optimization_time = time.time() - t1        if debug:            print(f"实例优化完成，用时: {optimization_time:.4f}s")    else:        if debug:            print("跳过实例优化 (max_iterations=0)")        optimized_flow    = initial_flow        optimization_time = 0.0    # 统一维度    if initial_flow.dim() == 4:        initial_flow = initial_flow.unsqueeze(0)    if optimized_flow.dim() == 4:        optimized_flow = optimized_flow.unsqueeze(0)    if initial_flow.shape[0] != batch_size:        initial_flow = initial_flow.repeat(batch_size, 1, 1, 1, 1)    if optimized_flow.shape[0] != batch_size:        optimized_flow = optimized_flow.repeat(batch_size, 1, 1, 1, 1)    if debug:        print(f"配准完成 | 初始流场: {initial_flow_time:.4f}s | 优化: {optimization_time:.4f}s")    return (        initial_flow.contiguous(),        optimized_flow.contiguous(),        initial_flow_time,        optimization_time,    )def run(opt):    setters.setSeed(0)    setters.setFoldersLoggers(opt)    setters.setGPU(opt)    test_loader = getters.getDataLoader(opt, split='test')    print(f"加载 UniGradICON 模型: {opt['model']} ...")    pretrained_model, _ = getters.getTestModelWithCheckpoints(opt)    if torch.cuda.is_available():        pretrained_model = pretrained_model.cuda().float()    pretrained_model.eval()    registration_config = {        'debug':          opt.get('debug', False),        'learning_rate':  opt.get('learning_rate', 0.025),        'max_iterations': opt.get('max_iterations', 10),        'grid_sp_adam':   opt.get('grid_sp_adam', 1),        'lambda_sim':     opt.get('lambda_sim', 1.0),        'lambda_reg':     opt.get('lambda_reg', 1.0),        'lambda_ssim':    opt.get('lambda_ssim', 2.0),    }    print("\n" + "=" * 80)    print("✓ 模型: UniGradICON")    print("配置参数:")    for k, v in registration_config.items():        print(f"  {k}: {v}")    print("=" * 80)    reg_model = registerSTModel(opt['img_size'], 'nearest').cuda()    # 评估指标    eval_dsc     = AverageMeter()    init_dsc     = AverageMeter()    eval_lv_dsc  = AverageMeter()    init_lv_dsc  = AverageMeter()    eval_rv_dsc  = AverageMeter()    init_rv_dsc  = AverageMeter()    eval_lvm_dsc = AverageMeter()    init_lvm_dsc = AverageMeter()    eval_jac_det = AverageMeter()    eval_std_det = AverageMeter()    eval_hd95    = AverageMeter()    init_hd95    = AverageMeter()    total_initial_flow_time = 0.0    total_optimization_time = 0.0    total_registration_time = 0.0    total_registrations     = 0    df_data = []    with torch.no_grad():        for data in test_loader:            sub_idx = data[6].item()            x, x_seg, y, y_seg, x_seg_mask, y_seg_mask = [Variable(t.cuda()) for t in data[:6]]            print("\n" + "=" * 80)            print(f"处理 Subject {sub_idx}")            print("=" * 80)            if torch.cuda.is_available():                torch.cuda.synchronize()            reg_start = time.time()            # 双向配准            initial_flow1, pos_flow1, init_time1, opt_time1 = unified_registration(                x, y, pretrained_model, registration_config            )            initial_flow2, pos_flow2, init_time2, opt_time2 = unified_registration(                y, x, pretrained_model, registration_config            )            if torch.cuda.is_available():                torch.cuda.synchronize()            registration_time = time.time() - reg_start            total_initial_flow_time += (init_time1 + init_time2)            total_optimization_time += (opt_time1  + opt_time2)            total_registration_time += registration_time            total_registrations     += 2            # Dice            def_out1 = reg_model(x_seg.cuda().float(), pos_flow1)            dsc1, rv_dsc1, lvm_dsc1, lv_dsc1 = dice_eval(                def_out1.long(), y_seg.long(), 4, output_individual=True            )            def_out2 = reg_model(y_seg.cuda().float(), pos_flow2)            dsc2, rv_dsc2, lvm_dsc2, lv_dsc2 = dice_eval(                def_out2.long(), x_seg.long(), 4, output_individual=True            )            dsc_p   = (dsc1   + dsc2)   / 2            rv_dsc  = (rv_dsc1  + rv_dsc2)  / 2            lvm_dsc = (lvm_dsc1 + lvm_dsc2) / 2            lv_dsc  = (lv_dsc1  + lv_dsc2)  / 2            eval_dsc.update(dsc_p.item(),   x.size(0))            eval_lv_dsc.update(lv_dsc.item(),  x.size(0))            eval_rv_dsc.update(rv_dsc.item(),  x.size(0))            eval_lvm_dsc.update(lvm_dsc.item(), x.size(0))            dsc_i, rv_dsci, lvm_dsci, lv_dsci = dice_eval(                x_seg.long(), y_seg.long(), 4, output_individual=True            )            init_dsc.update(dsc_i.item(),     x.size(0))            init_lv_dsc.update(lv_dsci.item(),  x.size(0))            init_rv_dsc.update(rv_dsci.item(),  x.size(0))            init_lvm_dsc.update(lvm_dsci.item(), x.size(0))            # Jacobian            jac_det1     = jacobian_determinant(pos_flow1.detach().cpu().numpy())            jac_det2     = jacobian_determinant(pos_flow2.detach().cpu().numpy())            jac_det_val  = (computeJacDetVal(jac_det1, x_seg.shape[2:])                            + computeJacDetVal(jac_det2, x_seg.shape[2:])) / 2            std_dev_jac  = (computeSDLogJ(jac_det1) + computeSDLogJ(jac_det2)) / 2            eval_jac_det.update(jac_det_val, x.size(0))            eval_std_det.update(std_dev_jac, x.size(0))            # HD95            moving_np     = x_seg.long().squeeze().cpu().numpy()            fixed_np      = y_seg.long().squeeze().cpu().numpy()            hd95_1 = compute_HD95(moving_np, fixed_np,                                   def_out1.long().squeeze().cpu().numpy(),                                   4, opt['voxel_spacing'])            hd95_2 = compute_HD95(y_seg.long().squeeze().cpu().numpy(),                                   x_seg.long().squeeze().cpu().numpy(),                                   def_out2.long().squeeze().cpu().numpy(),                                   4, opt['voxel_spacing'])            hd95 = (hd95_1 + hd95_2) / 2            eval_hd95.update(hd95, x.size(0))            init_hd95_val = compute_HD95(moving_np, fixed_np, moving_np, 4, opt['voxel_spacing'])            init_hd95.update(init_hd95_val, x.size(0))            avg_init_time = (init_time1 + init_time2) / 2            avg_opt_time  = (opt_time1  + opt_time2)  / 2            improvement = dsc_p.item() - dsc_i.item()            status = "优秀" if dsc_p.item() >= 0.80 else "良好" if dsc_p.item() >= 0.78 else "待优化"            print(f"{status} Subject {sub_idx} | dice: {dsc_p:.4f} ({improvement:+.4f}), "                  f"init: {dsc_i:.4f}, init_time: {avg_init_time:.4f}s, "                  f"opt_time: {avg_opt_time:.4f}s, total_time: {registration_time:.4f}s")            df_data.append([                sub_idx, dsc_p.item(), dsc_i.item(),                rv_dsc.item(), lvm_dsc.item(), lv_dsc.item(),                jac_det_val, std_dev_jac, hd95, init_hd95_val,                avg_init_time, avg_opt_time, registration_time            ])            # 保存配准结果            if opt['is_save']:                fp_flow    = os.path.join('logs', opt['dataset'], 'UniGradICON_Optimized', 'flow_fields')                fp_initial = os.path.join('logs', opt['dataset'], 'UniGradICON_Optimized', 'initial_flows')                fp_warped  = os.path.join('logs', opt['dataset'], 'UniGradICON_Optimized', 'warped_images')                for p in [fp_flow, fp_initial, fp_warped]:                    os.makedirs(p, exist_ok=True)                prefix = str(sub_idx).zfill(3)                nib.save(nib.Nifti1Image(initial_flow1.permute(2, 3, 4, 1, 0).cpu().numpy(), None),                         os.path.join(fp_initial, f'{prefix}_initial_flow_x2y.nii.gz'))                nib.save(nib.Nifti1Image(initial_flow2.permute(2, 3, 4, 1, 0).cpu().numpy(), None),                         os.path.join(fp_initial, f'{prefix}_initial_flow_y2x.nii.gz'))                nib.save(nib.Nifti1Image(pos_flow1.permute(2, 3, 4, 1, 0).cpu().numpy(), None),                         os.path.join(fp_flow, f'{prefix}_flow_x2y.nii.gz'))                nib.save(nib.Nifti1Image(pos_flow2.permute(2, 3, 4, 1, 0).cpu().numpy(), None),                         os.path.join(fp_flow, f'{prefix}_flow_y2x.nii.gz'))                warped_x = reg_model(x.cuda().float(), pos_flow1)                warped_y = reg_model(y.cuda().float(), pos_flow2)                nib.save(nib.Nifti1Image(warped_x.squeeze().cpu().numpy(), None),                         os.path.join(fp_warped, f'{prefix}_warped_x2y.nii.gz'))                nib.save(nib.Nifti1Image(warped_y.squeeze().cpu().numpy(), None),                         os.path.join(fp_warped, f'{prefix}_warped_y2x.nii.gz'))                print(f"  ✓ 已保存配准结果 (Subject {sub_idx})")    # ── 汇总统计 ──────────────────────────────────────────────────────────────    overall_improvement = eval_dsc.avg - init_dsc.avg    status = "优秀" if eval_dsc.avg >= 0.80 else ("良好" if eval_dsc.avg >= 0.78 else "待优化")    avg_init_time  = total_initial_flow_time / total_registrations if total_registrations > 0 else 0    avg_opt_time   = total_optimization_time / total_registrations if total_registrations > 0 else 0    avg_total_time = total_registration_time / len(test_loader)    if len(test_loader)    > 0 else 0    print("\n" + "=" * 80)    print("最终结果统计 [UniGradICON]")    print("=" * 80)    print(f"{status}: Dice {init_dsc.avg:.4f} ➜ {eval_dsc.avg:.4f} ({overall_improvement:+.4f})")    print(f"分项: rv={eval_rv_dsc.avg:.4f}, lvm={eval_lvm_dsc.avg:.4f}, lv={eval_lv_dsc.avg:.4f}")    print(f"形变质量: jac_det={eval_jac_det.avg:.6f}, std_dev={eval_std_det.avg:.4f}")    print(f"边界精度: hd95={eval_hd95.avg:.4f} (init: {init_hd95.avg:.4f})")    print("\n" + "=" * 80)    print("时间统计")    print("=" * 80)    print(f"初始流场预测总时间: {total_initial_flow_time:.3f}s")    print(f"实例优化总时间:     {total_optimization_time:.3f}s")    print(f"完整配准总时间:     {total_registration_time:.3f}s")    print(f"平均初始流场时间:   {avg_init_time:.4f}s/配准")    print(f"平均实例优化时间:   {avg_opt_time:.4f}s/配准")    print(f"平均完整配准时间:   {avg_total_time:.4f}s/样本")    print(f"总配准次数:         {total_registrations}（{len(test_loader)} 样本 × 2 方向）")    print("=" * 80)    df_data.append([        'Average', eval_dsc.avg, init_dsc.avg,        eval_rv_dsc.avg, eval_lvm_dsc.avg, eval_lv_dsc.avg,        eval_jac_det.avg, eval_std_det.avg, eval_hd95.avg, init_hd95.avg,        avg_init_time, avg_opt_time, avg_total_time    ])    keys = ['subject', 'dice', 'init_dice', 'rv_dice', 'lvm_dice', 'lv_dice',            'jac_det', 'std_dev_jac', 'hd95', 'init_hd95',            'init_time', 'opt_time', 'total_time']    df = pd.DataFrame(df_data, columns=keys)    fp = os.path.join('logs', opt['dataset'], 'results_UniGradICON_Optimized.csv')    os.makedirs(os.path.dirname(fp), exist_ok=True)    df.to_csv(fp, index=False)    print(f"\n✓ 结果已保存至: {fp}")if __name__ == '__main__':    opt = {        'img_size':      (128, 128, 16),        'in_shape':      (128, 128, 16),        'logs_path':     './logs',        'num_workers':   4,        'voxel_spacing': (1.8, 1.8, 10),    }    parser = argparse.ArgumentParser(description="UniGradICON + 实例优化框架（ACDC心脏数据集）")    parser.add_argument("-m",  "--model",         type=str,   default='UniGradICON')    parser.add_argument("-bs", "--batch_size",    type=int,   default=1)    parser.add_argument("-d",  "--dataset",       type=str,   default='acdcreg')    parser.add_argument("--gpu_id",               type=str,   default='0')    parser.add_argument("-dp", "--datasets_path", type=str,   default="/data2/cl/datasets/")    parser.add_argument("--is_save",              type=int,   default=1)    parser.add_argument("--num_classes",          type=int,   default=4)    parser.add_argument("--log",                  type=str,   default="./logs/acdcreg/UniGradICON")    # 实例优化参数    parser.add_argument("--debug",                type=bool,  default=True)    parser.add_argument("--learning_rate",        type=float, default=0.025)    parser.add_argument("--lambda_sim",           type=float, default=1.0)    parser.add_argument("--lambda_reg",           type=float, default=1.0)    parser.add_argument("--lambda_ssim",          type=float, default=2.0)    parser.add_argument("--max_iterations",       type=int,   default=10)    parser.add_argument("--grid_sp_adam",         type=int,   default=1)    args, unknowns = parser.parse_known_args()    opt = {**opt, **vars(args)}    opt['nkwargs'] = {s.split('=')[0]: s.split('=')[1] for s in unknowns}    print("\n" + "=" * 80)    print("✓ UniGradICON + 实例优化框架（ACDC心脏数据集）")    print("=" * 80)    run(opt)